class HomePage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    final authBloc = BlocProvider.of<AuthBloc>(context);
    return BlocConsumer<AuthBloc, AuthState>(
      listener: (context, state) {
        if (state.status == AuthStatus.unauthenticated) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(content: Text('Logged out!')),
          );
        } else if (state.status == AuthStatus.authenticated) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(content: Text('Welcome ${state.userId}')),
          );
        }
      },
      builder: (context, state) {
        if (state.status == AuthStatus.unknown) {
          return Scaffold(body: Center(child: CircularProgressIndicator()));
        } else if (state.status == AuthStatus.authenticated) {
          return Scaffold(
            appBar: AppBar(title: Text('Dashboard')),
            body: Center(
              child: Column(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  Text('Logged in as user: ${state.userId}'),
                  SizedBox(height: 20),
                  ElevatedButton(
                    onPressed: () => authBloc.add(LoggedOut()),
                    child: Text('Logout'),
                  ),
                ],
              ),
            ),
          );
        } else {
          return LoginPage();
        }
      },
    );
  }
}

class LoginPage extends StatelessWidget {
  final TextEditingController emailController = TextEditingController();
  final TextEditingController passwordController = TextEditingController();

  @override
  Widget build(BuildContext context) {
    final authBloc = BlocProvider.of<AuthBloc>(context);
    return Scaffold(
      appBar: AppBar(title: Text('Login')),
      body: Padding(
        padding: EdgeInsets.all(16.0),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            TextField(
              controller: emailController,
              decoration: InputDecoration(labelText: 'Email'),
            ),
            TextField(
              controller: passwordController,
              obscureText: true,
              decoration: InputDecoration(labelText: 'Password'),
            ),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: () async {
                final success = await authBloc.authRepository.login(
                  emailController.text,
                  passwordController.text,
                );
                if (success) {
                  final tokens = await authBloc.authRepository.getTokens();
                  authBloc.add(LoggedIn(
                    userId: emailController.text,
                    accessToken: tokens['access_token']!,
                    refreshToken: tokens['refresh_token']!,
                  ));
                } else {
                  ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(content: Text('Invalid credentials')),
                  );
                }
              },
              child: Text('Login'),
            ),
          ],
        ),
      ),
    );
  }
}

